/**
 * @param {string} base64Image
 * @param {MxObject} imageDimensions
 * @param {string} orientation
 * @returns {Promise.<string>}
 */
export async function JS_ImageToPDF(base64Image, imageDimensions, orientation) {
	// BEGIN USER CODE
    var height = imageDimensions.get('Height');
    var width = imageDimensions.get('Width');
    var doc = new jsPDF(orientation, 'px', [width, height]);
    doc.addImage(base64Image, 0, 0, width, height);
    var out = doc.output('datauristring');
    out = out.split("base64,")[1];
    return out;
	// END USER CODE
}
